class Solution:
    def mergeSort(self, head: ListNode) -> ListNode:
        if not head or not head.next: return head
        slow = fast = head
        while fast.next and fast.next.next:
            slow = slow.next
            fast = fast.next.next
        mid = slow
        prev = None
        while mid != head:
            prev = mid
            mid = mid.next
        prev.next = None
        left = head
        right = mid
        def merge(l, r):
            dummy = ListNode()
            curr = dummy
            while l and r:
                if l.val < r.val:
                    curr.next = l
                    l = l.next
                else:
                    curr.next = r
                    r = r.next
                curr = curr.next
            curr.next = l or r
            return dummy.next
        return merge(mergeSort(left), mergeSort(right))
